// Blog/page.js

const Blog = () => {
 return (
  &lt;>
   &lt;h2>Blog&lt;/h2>
   &lt;p>Dies ist ein Blog&lt;/p>
  &lt;/>
  )
}

export default Blog;

// Blog/layout.js

async function getPosts() {
 // Hier wird das Laden ĂĽber eine API simuliert
 return [
  {slug: 'nextjs-rocks', title: 'Warum Next.js rockt'},
  {slug: 'react-hooks', title: 'React Hooks erklĂ¤rt'},
  {slug: 'css-modules', title: 'CSS Modules in Next.js'},
 ];
}

const LayoutBlog = async ({children}) => {
 const posts = await getPosts();
 return (
  &lt;>
   &lt;aside>
    &lt;nav>
     &lt;/* Statische Route */>
     &lt;a href={'/Blog/overview'}>Overview&lt;/a>&lt;br />

     &lt;/* Dynamische Routen */>
     {
      posts.map(post => (
       &lt;>
        &lt;a href={`/Blog/${post.slug}`} key={post.slug}>{post.title}&lt;/a>&lt;br />
       &lt;/>
      ))
     }
    &lt;/nav>
   &lt;/aside>
   &lt;main>{children}&lt;/main>
  &lt;/>
 )
}

export default LayoutBlog

// Blog/[slug]/page.js

async function getPost(slug) {
 // Hier wird simuliert, dass der Blog-Beitrag aus einer API geladen wird
 const posts = [
  {
   slug: 'nextjs-rocks', 
   title: 'Warum Next.js rockt', 
   excerpt: 'Ein tiefgehender Blick...', 
   content: 'Next.js ist ein React-Framework, blah blah blah.'
  }, {
   ... mehr Content
  }
 ];
 return posts.find(post => post.slug === slug);
}

const Blogpost = async ({params}) => {
 const {slug} = await params;
 const post = await getPost(slug);

 if (!post) {
  return &lt;h3>Post nicht gefunden&lt;/h3>;
 }

 return (
  &lt;>
   &lt;h3>{post.title}&lt;/h3>
   &lt;p>&lt;em>{post.excerpt}&lt;/em>&lt;/p>
   &lt;p>{post.content}&lt;/p>
  &lt;/>
 )
}

export default Blogpost;

// Blog/Overview/page.js

const Overview = () => {
 return (
  &lt;>
   &lt;h1>Ăśberblick&lt;/h1>
   &lt;p>Hier irgendein Inhalt&lt;/p>
  &lt;/>
 )
}

export default Overview
